const consumedByQid=new Map(); // file -> qid that already claimed it
for(const r of reviewsMeta){
  if(r.file && r.parsed && r.parsed.popped_by_queue_id!=null){
    consumedByQid.set(r.file,r.parsed.popped_by_queue_id);
  }
}
// (reviewsMeta pre-parse must also stash r.parsed = the whole object)

const claimsToWrite=[]; // [{file, qid}] — flush after filter

