    typeof item.operator_bypass_reason==='string' && item.operator_bypass_reason.length>0;

  const realMatch=strictRev||softRev;
  const shouldPop=!!realMatch||operatorBypass;

  if(shouldPop){
    const claimedFile=realMatch?realMatch.file:null;
    if(claimedFile){
